'use strict';
// Emit quest-decks.js (a browser-loadable `const questDecksData = {…}`) from the
// validated quest-decks.json. Same reason as quest-overlay.js: the app is
// zero-build and runs from file://, where fetch() of a .json is blocked, so the
// baked D3 decks reach the client as a global defined in a plain <script>.
//
//   node scripts/build-quest-decks-js.js
//
// Re-run whenever quest-decks.json changes (i.e. after generate-quest-decks.js
// --apply). The JSON stays the source of truth (validated by validate-data.js);
// this file is generated output.

const fs = require('fs');
const path = require('path');
const { ROOT } = require('./lib');

const jsonPath = path.join(ROOT, 'quest-decks.json');
if (!fs.existsSync(jsonPath)) {
  console.error('quest-decks.json not found — run scripts/generate-quest-decks.js --apply first.');
  process.exit(1);
}
const data = JSON.parse(fs.readFileSync(jsonPath, 'utf8'));
const banner = '// GENERATED by scripts/build-quest-decks-js.js from quest-decks.json — do not edit by hand.\n';
const body = banner + 'const questDecksData = ' + JSON.stringify(data) + ';\n';
fs.writeFileSync(path.join(ROOT, 'quest-decks.js'), body);
console.log(`Wrote quest-decks.js: ${Object.keys(data).length} baked deck(s).`);
